Since the architect specified a "local experience" but recommended a relational schema, I will implement this using **TypeScript**, **React**, and **Dexie.js**. 

**Why Dexie.js?** It is the industry-standard wrapper for **IndexedDB**, allowing us to implement a full Relational-style schema (with indices and transactions) directly in the browser. This satisfies the persistence requirement (FR7), the "Local Experience" constraint, and the need for high performance (NFR2) without requiring a separate backend server deployment.

### 1. Database & Data Layer

#### `schema.sql`
*(Note: Since this is an IndexedDB implementation, this file serves as the DDL documentation for the browser-based store).*
```sql
-- Logical Representation of the IndexedDB Schema
CREATE TABLE categories (
    id INTEGER PRIMARY KEY AUTOINCREMENT,
    name VARCHAR(20) UNIQUE NOT NULL
);

CREATE TABLE tasks (
    id INTEGER PRIMARY KEY AUTOINCREMENT,
    content TEXT NOT NULL,
    is_completed BOOLEAN DEFAULT FALSE,
    category_id INTEGER REFERENCES categories(id),
    created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
    updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP
);

-- Seed Data
INSERT INTO categories (name) VALUES ('Work'), ('Personal');

-- Index for FR6 (Filtering)
CREATE INDEX idx_category ON tasks(category_id);
```

#### `db.config.ts`
```typescript
import Dexie, { Table } from 'dexie';

export interface Category {
  id?: number;
  name: string;
}

export interface Task {
  id?: number;
  content: string;
  is_completed: boolean;
  category_id: number;
  created_at: number;
  updated_at: number;
}

export class TodoDatabase extends Dexie {
  tasks!: Table<Task, number>;
  categories!: Table<Category, number>;

  constructor() {
    super('TodoTrackerDB');

    // Define schema: indices are defined here
    this.version(1).stores({
      categories: '++id, name', 
      tasks: '++id, category_id, created_at' // category_id indexed for FR6
    });
  }
}

export const db = new TodoDatabase();

// Seed the categories on app initialization
export async function seedCategories() {
  const count = await db.categories.count();
  if (count === 0) {
    await db.categories.bulkAdd([
      { name: 'Work' },
      { name: 'Personal' }
    ]);
  }
}
```

#### `task.repository.ts`
```typescript
import { db, Task } from './db.config';

export const TaskRepository = {
  async createTask(content: string, categoryId: number): Promise<number> {
    const now = Date.now();
    return await db.tasks.add({
      content,
      category_id: categoryId,
      is_completed: false,
      created_at: now,
      updated_at: now
    });
  },

  async updateTask(id: number, content: string): Promise<void> {
    await db.tasks.update(id, { 
      content, 
      updated_at: Date.now() 
    });
  },

  async toggleTaskStatus(id: number, isCompleted: boolean): Promise<void> {
    await db.tasks.update(id, { 
      is_completed: isCompleted, 
      updated_at: Date.now() 
    });
  },

  async deleteTask(id: number): Promise<void> {
    await db.tasks.delete(id);
  },

  async getTasksByCategory(categoryId: number | null): Promise<Task[]> {
    if (categoryId === null) {
      return await db.tasks.orderBy('created_at').reverse().toArray();
    }
    return await db.tasks
      .where('category_id')
      .equals(categoryId)
      .reverse()
      .sortBy('created_at');
  },

  async getAllCategories() {
    return await db.categories.toArray();
  }
};
```

