### 2. Business Logic Layer

#### `task.service.ts`
```typescript
import { TaskRepository } from './task.repository';
import { Task, Category } from './db.config';

export const TaskService = {
  async createNewTask(content: string, categoryId: number) {
    if (!content.trim()) throw new Error("Task content cannot be empty");

    // Validation: Ensure category exists
    const category = await db.categories.get(categoryId);
    if (!category) throw new Error("Invalid Category Selected");

    return await TaskRepository.createTask(content, categoryId);
  },

  async editTask(id: number, content: string) {
    return await TaskRepository.updateTask(id, content);
  },

  async toggleComplete(id: number, currentStatus: boolean) {
    return await TaskRepository.toggleTaskStatus(id, !currentStatus);
  },

  async removeTask(id: number) {
    return await TaskRepository.deleteTask(id);
  },

  async fetchTasks(filterCategory: string | 'All') {
    const categories = await TaskRepository.getAllCategories();

    if (filterCategory === 'All') {
      return await TaskRepository.getTasksByCategory(null);
    }

    const category = categories.find(c => c.name === filterCategory);
    if (!category) return [];

    return await TaskRepository.getTasksByCategory(category.id!);
  }
};
```

