### 4. Frontend Components

#### `TaskStore.ts`
*(Implementing Optimistic UI updates to satisfy NFR2: Perceived Zero-Latency).*
```typescript
import { create } from 'zustand';
import { Task } from './db.config';
import { TaskController } from './task.controller';

interface TaskState {
  tasks: Task[];
  filter: string;
  setFilter: (filter: string) => void;
  setTasks: (tasks: Task[]) => void;

  // Optimistic Actions
  addTask: (content: string, catId: number) => Promise<void>;
  toggleTask: (id: number) => Promise<void>;
}

export const useTaskStore = create<TaskState>((set, get) => ({
  tasks: [],
  filter: 'All',
  setFilter: (filter) => set({ filter }),
  setTasks: (tasks) => set({ tasks }),

  addTask: async (content, catId) => {
    const tempId = Date.now();
    const newTask: Task = { 
      id: tempId, content, category_id: catId, 
      is_completed: false, created_at: Date.now(), updated_at: Date.now() 
    };

    // Optimistic Update
    set((state) => ({ tasks: [newTask, ...state.tasks] }));

    try {
      await TaskController.handleAddTask(content, catId);
      // Refresh from DB to get real ID
      const freshTasks = await TaskController.handleGetTasks(get().filter);
      set({ tasks: freshTasks });
    } catch (err) {
      set((state) => ({ tasks: state.tasks.filter(t => t.id !== tempId) }));
    }
  },

  toggleTask: async (id) => {
    const { tasks } = get();
    const task = tasks.find(t => t.id === id);
    if (!task) return;

    // Optimistic Update
    set((state) => ({
      tasks: state.tasks.map(t => t.id === id ? { ...t, is_completed: !t.is_completed } : t)
    }));

    try {
      await TaskController.handleToggleTask(id, task.is_completed);
    } catch (err) {
      set({ tasks }); // Rollback
    }
  }
}));
```

#### `TaskItem.jsx`
```jsx
import React from 'react';
import { useTaskStore } from './TaskStore';

const TaskItem = ({ task }) => {
  const { toggleTask } = useTaskStore();

  return (
    <div className={`task-item ${task.is_completed ? 'completed' : ''}`}>
      <div className="task-content-wrapper">
        <input 
          type="checkbox" 
          checked={task.is_completed} 
          onChange={() => toggleTask(task.id)} 
        />
        <span className="task-text">{task.content}</span>
      </div>
      <div className="task-meta">
        {task.category_id === 1 ? <span className="badge work">Work</span> : <span className="badge personal">Personal</span>}
      </div>
    </div>
  );
};

export default TaskItem;
```

#### `FilterBar.jsx`
```jsx
import React from 'react';
import { useTaskStore } from './TaskStore';

const FilterBar = () => {
  const { filter, setFilter } = useTaskStore();
  const options = ['All', 'Work', 'Personal'];

  return (
    <div className="filter-bar">
      {options.map(opt => (
        <button 
          key={opt} 
          className={filter === opt ? 'active' : ''} 
          onClick={() => setFilter(opt)}
        >
          {opt}
        </button>
      ))}
    </div>
  );
};

export default FilterBar;
```

